name: CI

on:
  push:

jobs:
  CI:
    runs-on: blacksmith-4vcpu-ubuntu-2404
    timeout-minutes: 8
    env:
      TURBO_TOKEN: ${{ secrets.TURBO_TOKEN }}
      TURBO_TEAM: ${{ secrets.TURBO_TEAM }}
      TURBO_REMOTE_ONLY: true
      GH_CLIENT_ID: ${{ secrets.GH_CLIENT_ID }}
      GH_CLIENT_SECRET: ${{ secrets.GH_CLIENT_SECRET }}
      BETTER_AUTH_SECRET: ${{ secrets.BETTER_AUTH_SECRET }}
      BETTER_AUTH_URL: ${{ secrets.BETTER_AUTH_URL }}
      API_KEY_ENCRYPTION_KEY: ${{ secrets.API_KEY_ENCRYPTION_KEY }}
      SLACK_BOT_TOKEN: ${{ secrets.SLACK_BOT_TOKEN }}
      TEST_CF_ACCOUNT_API_KEY: ${{ secrets.TEST_CF_ACCOUNT_API_KEY }}
      TEST_CF_ACCOUNT_MISSING_OBSERVABILITY_API_KEY: ${{ secrets.TEST_CF_ACCOUNT_MISSING_OBSERVABILITY_API_KEY }}
      TEST_CF_USER_API_KEY: ${{ secrets.TEST_CF_USER_API_KEY }}
      TEST_CF_USER_ALL_READ_API_KEY: ${{ secrets.TEST_CF_USER_ALL_READ_API_KEY }}
      TEST_CF_USER_MISSING_LIST_API_KEY: ${{ secrets.TEST_CF_USER_MISSING_LIST_API_KEY }}
      TEST_CF_USER_MISSING_OBSERVABILITY_API_KEY: ${{ secrets.TEST_CF_USER_MISSING_OBSERVABILITY_API_KEY }}
      TEST_CF_USER_SINGLE_ACCOUNT_API_KEY: ${{ secrets.TEST_CF_USER_SINGLE_ACCOUNT_API_KEY }}
      TEST_CF_LIMITED_PERMISSIONS_USER_API_KEY: ${{ secrets.TEST_CF_LIMITED_PERMISSIONS_USER_API_KEY }}
      CLICKHOUSE_URL: ${{ secrets.CLICKHOUSE_URL }}
      CLICKHOUSE_DB: ${{ secrets.CLICKHOUSE_DB }}
      CLICKHOUSE_USERNAME: ${{ secrets.CLICKHOUSE_USERNAME }}
      CLICKHOUSE_PASSWORD: ${{ secrets.CLICKHOUSE_PASSWORD }}
      LINEAR_TEST_API_KEY: ${{ secrets.LINEAR_TEST_API_KEY }}

    steps:
      - name: Checkout
        uses: actions/checkout@v3

      - name: Setup Node
        uses: ./.github/actions/setup

      - name: Install Doppler CLI
        uses: dopplerhq/cli-action@v2

      - run: bun turbo run lint test type-check build --dry-run=json  > dry-run.json
        if: ${{ github.run_attempt > 1 }}

      - uses: actions/upload-artifact@v4
        if: ${{ github.run_attempt > 1 }}
        with:
          name: ci-turbo-dry
          path: dry-run.json

      # - run: bun run e2e
      #   working-directory: apps/ingest

      - run: bun turbo run lint test type-check build --output-logs new-only --summarize --concurrency 10

      - uses: actions/upload-artifact@v4
        if: always()
        with:
          name: ci-turbo-runs
          path: .turbo/

  CD:
    runs-on: blacksmith-4vcpu-ubuntu-2404
    # if: ${{ github.event_name  == 'push' }}
    if: ${{ github.ref == 'refs/heads/main' }}
    needs: [CI]
    env:
      TURBO_TOKEN: ${{ secrets.TURBO_TOKEN }}
      TURBO_TEAM: ${{ secrets.TURBO_TEAM }}

    steps:
      - name: Checkout
        uses: actions/checkout@v3

      - name: Setup Node
        uses: ./.github/actions/setup

      - name: Deploy
        run: bun turbo run deploy  --output-logs new-only --summarize --continue
        env:
          CLOUDFLARE_API_TOKEN: ${{ secrets.CLOUDFLARE_API_TOKEN }}
          CLOUDFLARE_ACCOUNT_ID: ${{ secrets.CLOUDFLARE_ACCOUNT_ID }}

      - uses: actions/upload-artifact@v4
        with:
          name: deploy-turbo-runs
          path: .turbo/
